const html = $input.first().json.data || $input.first().json;
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);
const match = htmlStr.match(/const REPORT_DATA = (\{[\s\S]+?\});[\s\n]*\/\//) || htmlStr.match(/const REPORT_DATA = (\{[\s\S]+?\})\s*\n/);
if (!match) throw new Error('REPORT_DATA not found');
let reportData;
try { reportData = JSON.parse(match[1]); } catch(e) { throw new Error('Parse failed: ' + e.message); }
const components = reportData.components || {};
const summary = {
  csov_score: reportData.csov_score || 0,
  prev_csov_score: reportData.previous_csov_score || 0,
  week: reportData.week_label || reportData.date_label || '',
  components: {
    serp: components.serp?.score || 0,
    ai_overview: components.ai_overview?.score || 0,
    llm: components.llm?.score || 0,
    earned_media: components.earned_media?.score || 0,
  },
  serp_negative: components.serp?.negative || 0,
  serp_positive: components.serp?.positive || 0,
  action_items: (reportData.action_items || reportData.serp_action_items || []).slice(0, 8),
  weakest_countries: Object.entries(reportData.countries || {})
    .sort((a,b) => (a[1].total||0) - (b[1].total||0)).slice(0,3)
    .map(([k,v]) => k + ' (' + (v.total||0) + ')'),
};
return [{ json: { summary } }];

const summary = $input.first().json.summary;
const prompt = `You are a social media strategist for iVisa, a visa facilitation service. Based on the weekly CSOV (Credibility Share of Voice) data below, generate specific, actionable social media recommendations.

CSOV DATA:
${JSON.stringify(summary, null, 2)}

Return ONLY valid JSON (no markdown, no code fences) in this exact format:
{
  "next_steps": ["step1", "step2", "step3", "step4", "step5"],
  "content_ideas": [
    {"icon": "🛡️", "title": "idea title", "detail": "why, which platform, what format", "pillar": "Social Proof", "platforms": ["Instagram", "TikTok"], "priority": "high"}
  ]
}

Rules:
- next_steps: 5 items directly tied to improving CSOV or addressing flagged issues
- content_ideas: 5 items, each mapped to: Social Proof, Educational, or Humor/Relatability/Entertainment
- Focus on: countering negative Reddit/BBB results, fees-as-value framing, government-independence messaging, security/trust
- Be specific to iVisa`;

const body = {
  model: "claude-haiku-4-5-20251001",
  max_tokens: 1200,
  messages: [{ role: "user", content: prompt }]
};

return [{ json: { body: JSON.stringify(body), summary } }];

const response = $input.first().json;
const text = response.content?.[0]?.text || '';
const summary = $('Build Claude Request').first().json.summary;

let recs;
try {
  const cleaned = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  recs = JSON.parse(cleaned);
} catch(e) {
  recs = {
    next_steps: [
      "Respond to the Reddit thread 'Was using ivisa a mistake' — it's ranking #1 for multiple reputation keywords this week.",
      "Publish a Social Proof carousel with verified Trustpilot reviews on Instagram and TikTok to counter negative SERP results.",
      "Create an Educational post explaining the iVisa service fee as a value-add: expert review, 24/7 support, error prevention.",
      "Publish a Security & Privacy explainer addressing data concerns flagged in Google AI Overviews.",
      "Pitch a travel blogger or YouTuber for an honest iVisa review — earned media needs third-party coverage boost."
    ],
    content_ideas: [
      {"icon":"🛡️","title":"'Why we charge a fee' — transparent breakdown","detail":"Short-form video explaining the value behind the fee. Directly addresses AI Overview criticism.","pillar":"Educational","platforms":["TikTok","Instagram","YouTube"],"priority":"high"},
      {"icon":"⭐","title":"Customer wins compilation","detail":"Carousel of real Trustpilot reviews with visa approval photos. Counter negative Reddit sentiment.","pillar":"Social Proof","platforms":["Instagram","Facebook","LinkedIn"],"priority":"high"},
      {"icon":"🏛️","title":"iVisa vs government portals — side by side","detail":"Infographic showing how iVisa complements official processes. Addresses 'not government' concern.","pillar":"Educational","platforms":["Instagram","LinkedIn"],"priority":"high"},
      {"icon":"🔒","title":"Your data is safe — here's exactly how","detail":"Reel walking through iVisa's security certifications. Counters AI Overview data concerns.","pillar":"Educational","platforms":["Instagram","TikTok"],"priority":"medium"},
      {"icon":"😅","title":"Visa chaos vs iVisa ease","detail":"Trending audio reel: chaotic government portal vs smooth iVisa. Humor/relatability angle.","pillar":"Humor/Relatability/Entertainment","platforms":["TikTok","Instagram"],"priority":"medium"}
    ]
  };
}

return [{ json: {
  next_steps: recs.next_steps || [],
  content_ideas: recs.content_ideas || [],
  csov_score: summary.csov_score,
  prev_csov_score: summary.prev_csov_score,
  components: summary.components,
  generated_at: new Date().toISOString(),
}}];

const ghFile = $('GitHub GET data.json').first().json;
const sha = ghFile.sha;
const currentContent = Buffer.from(ghFile.content.replace(/\n/g,''), 'base64').toString('utf8');
let current = {};
try { current = JSON.parse(currentContent); } catch(e) { current = {}; }
const recs = $('Parse Recommendations').first().json;
const newData = {
  ...current,
  meta: { ...current.meta, last_updated: new Date().toISOString(), generated_by: 'n8n + claude-ai' },
  brand_reputation: {
    embed_url: (current.brand_reputation || {}).embed_url || 'https://paulavotobernales-94.github.io/-ivisa-csov/index.html',
    csov_score: recs.csov_score,
    prev_csov_score: recs.prev_csov_score,
    components: recs.components,
    next_steps: recs.next_steps,
    content_ideas: recs.content_ideas,
    last_updated: recs.generated_at,
  },
  content_ideas: {
    status: 'active',
    source: 'csov + claude-ai',
    last_updated: recs.generated_at,
    ideas: recs.content_ideas,
  },
};
const encoded = Buffer.from(JSON.stringify(newData, null, 2), 'utf8').toString('base64');
return [{ json: { content: encoded, sha } }];
